+type limitedLogBuffer struct {
+	mu        sync.Mutex
+	buf       bytes.Buffer
+	limit     int
+	truncated bool
+}
+
+func newLimitedLogBuffer(limit int) *limitedLogBuffer {
+	if limit <= 0 {
+		limit = 8 * 1024
+	}
+	return &limitedLogBuffer{limit: limit}
+}
+
+func (b *limitedLogBuffer) Write(p []byte) (int, error) {
+	b.mu.Lock()
+	defer b.mu.Unlock()
+
+	originalLen := len(p)
+	if b.limit <= 0 {
+		return originalLen, nil
+	}
+	remaining := b.limit - b.buf.Len()
+	if remaining <= 0 {
+		b.truncated = true
+		return originalLen, nil
+	}
+	if len(p) > remaining {
+		p = p[:remaining]
+		b.truncated = true
+	}
+	_, _ = b.buf.Write(p)
+	return originalLen, nil
+}
+
+func (b *limitedLogBuffer) String() string {
+	b.mu.Lock()
+	defer b.mu.Unlock()
+
+	if !b.truncated {
+		return b.buf.String()
+	}
+	return b.buf.String() + "\n...[truncated]"
+}
